11→export const handleCLickContent = (navigate) => {
12→    return (
13→        e,
14→        jsonbContent,
15→        wholeText,
16→        title,
17→        userId,
18→        name,
19→        avatar,
20→        created_at,
21→        journalId,
22→        isLiked,
23→        commentsCount,
24→        isBookmarked,
25→        likesCount,
26→        bookmarksCount,
27→        badge,
28→        postType = null,
29→        userReaction = null,
