77→export const handleClickProfile = (navigate) => {
78→    return(e, loggedInUserId, clickedUserId, clickedUsername) =>{
79→        if(loggedInUserId === clickedUserId){
80→            navigate('/profile');
81→        } else if(clickedUsername){
82→            navigate(`/u/${clickedUsername}`, {
83→                state: {
84→                    userId: clickedUserId
85→                }
86→            })
87→        } else {
88→            navigate(`/visitProfile?userId=${clickedUserId}`, {
89→                state: {
90→                    userId: clickedUserId
91→                }
92→            })
93→        }
94→    }
95→}
